-- Plantilles de notificacions per al mòdul d'ofertes laborals i candidatures
	-- Notificació - Canvi d''estat d''oferta laboral
	 ('c79e5db6-d89d-487f-a4ff-6e2801f7ade5', NOW(), NOW(), '1', '1', NULL, 'Notificació - Canvi d''estat d''oferta laboral', 'Plantilla per notificar canvis d''estat en ofertes laborals.', 'Canvi d''estat de l''oferta laboral: $stic_job_offers_name', 'Benvolgut/da,\r\n\r\nL''estat de l''oferta laboral $stic_job_offers_name ha canviat a $stic_job_offers_status.', 
	 '<p>Benvolgut/da,</p>
	 <p>L''estat de l''oferta laboral <strong>$stic_job_offers_name</strong> ha canviat a <strong><span style="background-color: #f1c40f;">$stic_job_offers_status</span></strong></p>',
	 0, '1', 0, 'notification'),
	 -- Notificació - Canvi d''estat de candidatura
	 ('8ec00c6b-6102-4eb4-a601-7cdb420676a3', NOW(), NOW(), '1', '1', NULL, 'Notificació - Canvi d''estat de candidatura', 'Plantilla per defecte per notificar canvis d''estat en candidatures.', 'Canvi d''estat de la candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $contact_full_name:\r\n\r\nS''ha canviat l''estat de la seva candidatura per a l''oferta laboral $stic_job_applications_stic_job_applications_stic_job_offers_name a $stic_job_applications_status.', '<p>Benvolgut/da $contact_full_name:</p>\n<p>S''ha canviat l''estat de la seva candidatura per a l''oferta laboral $stic_job_applications_stic_job_applications_stic_job_offers_name a $stic_job_applications_status.</p>', 0, '1', 0, 'notification'),
	 -- Candidatura - Notificació - Estat Acceptada
	 ('6a31f063-2d17-4fd6-aef1-9e15db0f7d11', NOW(), NOW(), '1', '1', NULL, 'Notificació - Candidatura acceptada', 'Plantilla per notificar que una candidatura ha estat acceptada.', 'La teva candidatura ha estat acceptada: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $contact_full_name:\r\n\r\nEns complau informar-te que la teva candidatura per a l''oferta laboral $stic_job_applications_stic_job_applications_stic_job_offers_name ha estat acceptada.\r\n\r\nEstat actual: $stic_job_applications_status.', '<p>Benvolgut/da $contact_full_name:</p>\n<p>Ens complau informar-te que la teva candidatura per a l''oferta laboral <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha estat acceptada.</p>\n<p>Estat actual: <strong>$stic_job_applications_status</strong>.</p>', 0, '1', 0, 'notification'),
	-- Candidatura - Notificació - Estat Rebutjada o tancada
	 ('bb6fe9c6-8b74-4526-a0a8-a7f4fd8e5960', NOW(), NOW(), '1', '1', NULL, 'Notificació - Candidatura rebutjada o tancada', 'Plantilla per notificar que una candidatura ha estat rebutjada o tancada.', 'Actualització de la teva candidatura: $stic_job_applications_stic_job_applications_stic_job_offers_name', 'Benvolgut/da $contact_full_name:\r\n\r\nLamentem comunicar-te que la teva candidatura per a l''oferta laboral $stic_job_applications_stic_job_applications_stic_job_offers_name ha passat a l''estat $stic_job_applications_status.\r\n\r\nGràcies pel teu interès.', '<p>Benvolgut/da $contact_full_name:</p>\n<p>Lamentem comunicar-te que la teva candidatura per a l''oferta laboral <strong>$stic_job_applications_stic_job_applications_stic_job_offers_name</strong> ha passat a l''estat <strong>$stic_job_applications_status</strong>.</p>\n<p>Gràcies pel teu interès.</p>', 0, '1', 0, 'notification'),
	 -- Oferta laboral - Notificació - Tancament vençut i estat no tancat
	('d3c1d5b7-f8d2-4df4-9f6b-2c63aa6b8e41', NOW(), NOW(), '1', '1', NULL, 'Notificació - Oferta amb tancament vençut sense estat tancada', 'Plantilla per notificar al responsable que l''oferta té el tancament de candidatures d''ahir i no està en estat tancada o similar.', 'Revisar oferta laboral: tancament de candidatures vençut - $stic_job_offers_name', 'Benvolgut/da,\r\n\r\nL''oferta laboral $stic_job_offers_name té la data de tancament de candidatures vençuda (ahir) i actualment està en estat $stic_job_offers_status.\r\n\r\nSi us plau, revisa l''oferta i actualitza''n l''estat si correspon.', '<p>Benvolgut/da,</p>\n<p>L''oferta laboral <strong>$stic_job_offers_name</strong> té la data de tancament de candidatures vençuda (ahir) i actualment està en estat <strong>$stic_job_offers_status</strong>.</p>\n<p>Si us plau, revisa l''oferta i actualitza''n l''estat si correspon.</p>', 0, '1', 0, 'notification');

